{
	const wchar_t * const s = L"wide load";
	std::string result = Catch::toString( s );
	CHECK( result == "\"wide load\"" );
}

{
	const wchar_t * s = L"wide load";
	std::string result = Catch::toString( s );
	CHECK( result == "\"wide load\"" );
}

{
	wchar_t * const s = L"wide load"const_cast<wchar_t* const>( L"wide load" );
	std::string result = Catch::toString( s );
	CHECK( result == "\"wide load\"" );
}

{
	wchar_t * s = L"wide load"const_cast<wchar_t*>( L"wide load" );
	std::string result = Catch::toString( s );
	CHECK( result == "\"wide load\"" );
}
